[{"operationName":"viewerLeagues","variables":{},"query":"query viewerLeagues {
  viewer {
    id
    __typename
    ... on Member {
      leagues {
        id
        slug
        isElectronicPaymentsEnabled
        __typename
      }
      __typename
    }
    ... on ExternalStaff {
      leagues {
        id
        slug
        __typename
      }
      __typename
    }
  }
}
"},{"operationName":"sidebar","variables":{},"query":"query sidebar {
  viewer {
    id
    ... on Member {
      leagues {
        id
        slug
        name
        isDefault
