[{"operationName":"viewerCountryQuery","variables":{},"query":"query viewerCountryQuery {
  viewer {
    id
    ... on Member {
      country {
        id
        __typename
      }
      __typename
    }
    __typename
  }
}
"},{"operationName":"Header","variables":{},"query":"query Header {
  viewer {
    id
    initials
    __typename
  }
}
"},{"operationName":"notificationBell","variables":{},"query":"query notificationBell {
  viewer {
    id
    notificationBellCount
    notifications(limit: 10) {
      id
      type
      title
      body
      isRead
      createdDate
      typeId
      metaData
      __typename
    }
    __typename
  }
}
"},{"operationName":"HeaderCartQueryQuery","variables":{},"query":"query HeaderCartQueryQuery {
  viewer {
    id
    ... on Member {
      leagues {
        id
        slug
        name
        isDefault
        isElectronicPaymentsEnabled
        __typename
      }
      membershipExpires
      setting(key: "DefaultLeague")
      fee {
        message
        discount
        year
        amount
        tax
        total
        __typename
      }
      leagues {
        id
        country {
          id
          __typename
        }
        __typename
      }
      __typename
    }
    __typename
  }
}
"},{"operationName":"ComponentFeatureCheck","variables":{"key":"Search"},"query":"query ComponentFeatureCheck($key: String!) {
  feature(key: $key)
}
"},{"operationName":"LiveStream","variables":{},"query":"query LiveStream {
  liveStream {
    __typename
    feeds {
      __typename
      ... on YoutubeLive {
        title
        description
        publishTime
        embed
        thumbnails {
          url
          height
          width
          __typename
        }
        __typename
      }
    }
  }
}
"},{"operationName":"leagueLayout","variables":{"slug":"RioGrandeValley"},"query":"query leagueLayout($slug: String!) {
  viewer {
    id
    ... on Member {
      leagues {
        id
        slug
        isElectronicPaymentsEnabled
        __typename
      }
      __typename
    }
    ... on ExternalStaff {
      leagues {
        id
        slug
        __typename
      }
      __typename
    }
    __typename
  }
  league(slug: $slug) {
    id
    name
    slug
    email
    phone
    homePageUrl
    facebookUrl
    officeHours
    logo
    byLaws {
      id
      url
      __typename
    }
    contacts(role: LO, status: ACTIVE) {
      displayName
      __typename
    }
    schedule(limit: 50) {
      ... on Tournament {
        id
        name
        startTime
        hostLocation {
          id
          address {
            id
            name
            __typename
          }
          __typename
        }
        __typename
      }
      ... on OtherEvent {
        id
        name
        startTime
        address {
          id
          name
          latitude
          longitude
          __typename
        }
        __typename
      }
      __typename
    }
    __typename
  }
}
"}]

